import React from "react";
import { Button } from "@mui/material";
import "./Sidebar.css";

interface SidebarProps {
    activeLink: string;
    onLinkClick: (link: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeLink, onLinkClick }) => {
    return (
        <div className="sidebar">
            <ul className="sidebar-menu">
                {["Real-Time Pricing", "Inventory", "Alerts", "Analytics", "Settings", "Help"].map((item) => (
                    <li key={item} className={activeLink === item ? "active" : ""} onClick={() => onLinkClick(item)}>
                        {item}
                    </li>
                ))}
            </ul>
            <Button variant="contained" color="error" className="logout-button">
                Logout
            </Button>
        </div>
    );
};

export default Sidebar;
